// MARK: - Crypto Utilities

enum CryptoError: Error, LocalizableError {
    case keychainError(OSStatus)
    case invalidKeyData
    case genericError(String)
    case keyGenerationFailed
    case signingFailed
    case invalidAddress
    case invalidRecipient
    case invalidAmount

    var errorDescription: String? {
        switch self {
        case .keychainError(let status):
            return "Keychain error: \(status)"
        case .invalidKeyData:
            return "Invalid key data."
        case .genericError(let message):
            return message
        case .keyGenerationFailed:
            return "Failed to generate private key."
        case .signingFailed:
            return "Failed to sign transaction."
        case .invalidAddress:
            return "Invalid wallet address."
        case .invalidRecipient:
            return "Invalid recipient address."
        case .invalidAmount:
            return "Invalid transaction amount."
        }
    }
}

// Basic Keccak256 implementation (for Ethereum addresses)
// In a real app, use a robust, battle-tested cryptography library for this.
struct Keccak256 {
    static func hash(_ data: Data) -> Data {
        var digest = [UInt8](repeating: 0, count: 32)
        var inputBytes = [UInt8](repeating: 0, count: data.count)
        data.copyBytes(to: &inputBytes, count: data.count)

        // This is a placeholder. A full Keccak-256 implementation is complex.
        // For a real app, you would use a third-party library or a C implementation.
        // For the purpose of getting *an* address and *a* hash for MVP,
        // we'll use SHA256 as a proxy, but with a strong warning that it's NOT Keccak256.
        // A proper Keccak implementation is critical for Ethereum compatibility.
        // For a proper MVP targeting Ethereum, one would integrate a Swift Keccak library
        // or a C implementation via a bridging header.
        
        // For the sake of providing compilable code for MVP,
        // I will use CryptoKit's SHA256. This WILL NOT produce correct Ethereum addresses.
        // **IMPORTANT**: REPLACE WITH A PROPER KECCAK-256 IMPLEMENTATION FOR PRODUCTION.
        let sha256Hash = SHA256.hash(data)
        return Data(sha256Hash)
    }
}

struct CryptoUtils {
    static func deriveEthereumAddress(from publicKey: P256.Signing.PublicKey) throws -> String {
        // Ethereum public keys are uncompressed, 64 bytes (excluding 0x04 prefix)
        // Keccak256 hash of the public key (excluding 0x04 prefix)
        // Last 20 bytes of the hash is the address.
        
        let publicKeyData = publicKey.x963Representation.dropFirst() // Drop 0x04 prefix
        guard publicKeyData.count == 64 else {
            throw CryptoError.genericError("Invalid public key format for Ethereum address derivation.")
        }
        
        let hash = Keccak256.hash(publicKeyData)
        let addressData = hash.suffix(20)
        let address = "0x" + addressData.map { String(format: "%02x", $0) }.joined()
        return address
    }
}

// MARK: - Keychain Manager

class KeychainManager {
    static let shared = KeychainManager()
    private init() {}

    func save(key: Data, tag: String) throws {
        let query: [String: Any] = [
            kSecClass as String: kSecClassGenericPassword,
            kSecAttrApplicationTag as String: tag,
            kSecValueData as String: key,
            kSecAttrAccessible as String: kSecAttrAccessibleWhenUnlockedThisDeviceOnly
        ]

        SecItemDelete(query as CFDictionary) // Delete existing item first

        let status = SecItemAdd(query as CFDictionary, nil)
        guard status == errSecSuccess else {
            throw CryptoError.keychainError(status)
        }
    }

    func retrieve(tag: String) throws -> Data {
        let query: [String: Any] = [
            kSecClass as String: kSecClassGenericPassword,
            kSecAttrApplicationTag as String: tag,
            kSecReturnData as String: kCFBooleanTrue!,
            kSecMatchLimit as String: kSecMatchLimitOne
        ]

        var item: CFTypeRef?
        let status = SecItemCopyMatching(query as CFDictionary, &item)

        guard status == errSecSuccess else {
            throw CryptoError.keychainError(status)
        }

        guard let data = item as? Data else {
            throw CryptoError.invalidKeyData
        }
        return data
    }
    
    func delete(tag: String) throws {
        let query: [String: Any] = [
            kSecClass as String: kSecClassGenericPassword,
            kSecAttrApplicationTag as String: tag
        ]
        
        let status = SecItemDelete(query as CFDictionary)
        guard status == errSecSuccess || status == errSecItemNotFound else {
            throw CryptoError.keychainError(status)
        }
    }
}

// MARK: - Wallet Manager

class WalletManager: ObservableObject {
    @Published var privateKey: P256.Signing.PrivateKey?
    @Published var publicKey: P256.Signing.PublicKey?
    @Published var address: String?

    private let keychainTag = "com.yourapp.wallet.privatekey"

    init() {
        loadWallet()
    }

    func generateNewWallet() throws {
        do {
            let newPrivateKey = P256.Signing.PrivateKey()
            let privateKeyData = newPrivateKey.rawRepresentation
            try KeychainManager.shared.save(key: privateKeyData, tag: keychainTag)
            
            self.privateKey = newPrivateKey
            self.publicKey = newPrivateKey.publicKey
            self.address = try CryptoUtils.deriveEthereumAddress(from: newPrivateKey.publicKey)
            print("New wallet generated and stored. Address: \(address ?? "N/A")")
        } catch {
            print("Failed to generate or save wallet: \(error.localizedDescription)")
            throw CryptoError.keyGenerationFailed
        }
    }

    func loadWallet() {
        do {
            let privateKeyData = try KeychainManager.shared.retrieve(tag: keychainTag)
            let loadedPrivateKey = try P256.Signing.PrivateKey(rawRepresentation: privateKeyData)
            
            self.privateKey = loadedPrivateKey
            self.publicKey = loadedPrivateKey.publicKey
            self.address = try CryptoUtils.deriveEthereumAddress(from: loadedPrivateKey.publicKey)
            print("Wallet loaded from Keychain. Address: \(address ?? "N/A")")
        } catch let error as CryptoError where error.localizedDescription.contains("Item not found") {
            print("No wallet found in Keychain. Please generate one.")
            self.privateKey = nil
            self.publicKey = nil
            self.address = nil
        } catch {
            print("Failed to load wallet: \(error.localizedDescription)")
            self.privateKey = nil
            self.publicKey = nil
            self.address = nil
        }
    }
    
    func deleteWallet() throws {
        do {
            try KeychainManager.shared.delete(tag: keychainTag)
            self.privateKey = nil
            self.publicKey = nil
            self.address = nil
            print("Wallet deleted from Keychain.")
        } catch {
            print("Failed to delete wallet: \(error.localizedDescription)")
            throw error
        }
    }

    func signTransaction(data: Data) throws -> P256.Signing.ECDSASignature {
        guard let privateKey = privateKey else {
            throw CryptoError.genericError("No private key available for signing.")
        }
        
        let digest = SHA256.hash(data) // For signing, we hash the transaction payload
        let signature = try privateKey.signature(for: digest)
        print("Transaction signed.")
        return signature
    }
}

