struct SendView: View {
    @ObservedObject var walletManager: WalletManager
    var blockchainService: BlockchainService
    
    @State private var recipientAddress: String = ""
    @State private var amountString: String = ""
    @State private var isSending = false
    @State private var errorMessage: String?
    @State private var showingAlert = false
    @Environment(\.dismiss) var dismiss

    var body: some View {
        Form {
            Section("Transaction Details") {
                TextField("Recipient Address", text: $recipientAddress)
                    .autocapitalization(.none)
                    .disableAutocorrection(true)
                
                TextField("Amount (ETH)", text: $amountString)
                    .keyboardType(.decimalPad)
            }
            
            Button {
                Task {
                    await sendTransaction()
                }
            } label: {
                if isSending {
                    ProgressView()
                } else {
                    Text("Sign & Send")
                }
            }
            .disabled(isSending || walletManager.privateKey == nil || recipientAddress.isEmpty || amountString.isEmpty)
        }
        .navigationTitle("Send Transaction")
        .alert("Transaction Status", isPresented: $showingAlert) {
            Button("OK", role: .cancel) { }
        } message: {
            Text(errorMessage ?? "An unknown error occurred.")
        }
    }
    
    private func sendTransaction() async {
        isSending = true
        errorMessage = nil

        guard let amount = Double(amountString), amount > 0 else {
            errorMessage = CryptoError.invalidAmount.localizedDescription
            showingAlert = true
            isSending = false
            return
        }

        // Basic validation for recipient address format (Ethereum-like)
        guard recipientAddress.hasPrefix("0x") && recipientAddress.count == 42 else {
            errorMessage = CryptoError.invalidRecipient.localizedDescription
            showingAlert = true
            isSending = false
            return
        }
        
        // For MVP, simplify transaction data. In a real Ethereum app,
        // this would involve RLP encoding, nonce, gas price, gas limit, chain ID, etc.
        let transactionPayload = "transfer:\(recipientAddress):amount:\(amount):from:\(walletManager.address ?? "")"
        guard let dataToSign = transactionPayload.data(using: .utf8) else {
            errorMessage = "Failed to encode transaction data."
            showingAlert = true
            isSending = false
            return
        }

        do {
            let signature = try walletManager.signTransaction(data: dataToSign)
            // For MVP, we're just sending the raw signature data + original payload hash.
            // A real app would construct a fully RLP-encoded transaction.
            var broadcastData = dataToSign
            broadcastData.append(signature.rawRepresentation)

            let txHash = try await blockchainService.broadcast(signedTransaction: broadcastData)
            errorMessage = "Transaction sent successfully! TX Hash: \(txHash)"
            showingAlert = true
            dismiss() // Go back to main view
        } catch {
            errorMessage = "Transaction failed: \(error.localizedDescription)"
            showingAlert = true
        }
        isSending = false
    }
}

